def clasificar_pieza(peso, nominal, tolerancia):
    return abs(peso - nominal) <= tolerancia


def procesar_lote(pesos, nominal, tolerancia):
    if not pesos:
        raise ValueError("El lote esta vacio.")
    conformes = 0
    rechazos = []
    for indice, peso in enumerate(pesos):
        if clasificar_pieza(peso, nominal, tolerancia):
            conformes += 1
        else:
            rechazos.append((indice, peso))
    conformidad = conformes / len(pesos) * 100
    return {"conformidad": conformidad, "rechazos": rechazos}


if __name__ == "__main__":
    lote = [100, 105, 92, 100, 101]
    resultado = procesar_lote(lote, nominal=100, tolerancia=3)
    print(f"Conformidad: {resultado['conformidad']:.1f}%")
    print("Rechazos:", resultado["rechazos"])

