def clasificar_pieza(peso, nominal, tolerancia):
    return abs(peso - nominal) <= tolerancia


def procesar_lote(pesos, nominal, tolerancia):
    if not pesos:
        raise ValueError("El lote esta vacio.")
    conformes = 0
    rechazos = []
    for indice, peso in enumerate(pesos):
        if clasificar_pieza(peso, nominal, tolerancia):
            conformes += 1
        else:
            rechazos.append((indice, peso))
    return {"conformidad": conformes / len(pesos) * 100, "rechazos": rechazos}


def generar_reporte(resultado):
    lineas = [f"Conformidad del lote: {resultado['conformidad']:.1f}%"]
    if resultado["rechazos"]:
        lineas.append("Piezas rechazadas (indice, peso):")
        for indice, peso in resultado["rechazos"]:
            lineas.append(f"  - #{indice}: {peso} g")
    else:
        lineas.append("Sin rechazos: lote totalmente conforme.")
    return "\n".join(lineas)


def main():
    lote = [100, 105, 92, 100, 101, 99]
    resultado = procesar_lote(lote, nominal=100, tolerancia=3)
    print(generar_reporte(resultado))


if __name__ == "__main__":
    main()

