from control_calidad import procesar_lote


def test_caso_normal():
    r = procesar_lote([100, 105, 92, 100], 100, 3)
    assert r["conformidad"] == 50.0, "CP1: conformidad incorrecta"
    assert r["rechazos"] == [(1, 105), (2, 92)], "CP1: rechazos incorrectos"


def test_frontera_incluye_limite():
    r = procesar_lote([103, 97], 100, 3)
    assert r["conformidad"] == 100.0, "CP2: el limite exacto debe ser conforme"


def test_lote_unitario():
    r = procesar_lote([100], 100, 3)
    assert r["conformidad"] == 100.0, "CP3: lote de una pieza"


def test_lote_vacio_lanza_error():
    try:
        procesar_lote([], 100, 3)
        assert False, "CP5: deberia lanzar ValueError"
    except ValueError:
        pass


if __name__ == "__main__":
    test_caso_normal()
    test_frontera_incluye_limite()
    test_lote_unitario()
    test_lote_vacio_lanza_error()
    print("Todas las pruebas pasaron.")

